#include "vrbitmaps.h"

/**
 * \brief Retrieves the appropriate color based on the system's appearance (dark or light mode).
 *
 * This function checks the system's appearance settings and returns a color
 * string suitable for the current mode:
 * - White (#FFFFFF) for dark mode.
 * - Dark gray (#444444) for light mode.
 *
 * \return A `wxString` containing the color code.
 */
wxString vrBitmaps::GetColor() {
    wxSystemAppearance s = wxSystemSettings::GetAppearance();
    if (s.IsDark()) {
        return "#FFFFFF";  // White for dark mode
    }
    return "#444444";  // Dark gray for light mode
}

