wxBitmap vrBitmaps::GetLogoBitmap(const wxSize& size, const wxColour& colour) {
    wxString my_bmp = wxString::Format(SvgLogo, colour.GetAsString(wxC2S_HTML_SYNTAX).ToStdString());
    return wxBitmapBundle::FromSVG(my_bmp, size).GetBitmap(size);
}